// Mistral Instruct v0.3 - classic [INST]/[/INST] turn format.
// Spec:
//   <s>[INST] {system_if_any}\n\n{user_turn_1} [/INST] {assistant_turn_1}</s>[INST] {user_turn_2} [/INST] ...
// There is no dedicated system role: the system message is prepended to the
// first user turn, separated from it by two newlines.  Each assistant reply is
// followed by the EOS token (</s>).
static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template &          tmpl,
        const autoparser::generation_params & inputs) {
    common_chat_params data;

    // Merge any leading system message into the first user turn.
    auto adjusted_messages = inputs.messages;
    workaround::system_message_not_supported(adjusted_messages);

    data.prompt  = common_chat_template_direct_apply_impl(tmpl, inputs,
                                                          /* messages_override = */ adjusted_messages);
    data.format  = COMMON_CHAT_FORMAT_PEG_NATIVE;
    data.supports_thinking = false;
    data.preserved_tokens  = {
        "[INST]",
        "[/INST]",
        "</s>",
    };

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        return p.literal(inputs.generation_prompt) + p.content(p.rest()) + p.end();
    });

    data.parser = parser.save();

    return data;
}

static json common_chat_extra_context() {
    json ctx = json::object();
    std::chrono::system_clock::time_point now = std::chrono::system_clock::now();
    std::string datetime_str = format_time(now, "%b %d %Y");
    std::string date_str = format_time(now, "%d %b %Y");
    ctx["datetime"] = datetime_str;
    ctx["date_string"] = date_str;
    return ctx;
}

